import{_ as a,c as s,a1 as t,o as i}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"Tránh Phát hiện Quét sử dụng Nhiều Địa chỉ IP Giả","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/5-NmapDecoyIP.md","filePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/5-NmapDecoyIP.md"}'),p={name:"vi/categories/ethical-hacking-labs/2-scanning-networks/5-NmapDecoyIP.md"};function c(e,n,h,o,r,l){return i(),s("div",null,n[0]||(n[0]=[t(`<h1 id="tranh-phat-hien-quet-su-dung-nhieu-đia-chi-ip-gia" tabindex="-1">Tránh Phát hiện Quét sử dụng Nhiều Địa chỉ IP Giả <a class="header-anchor" href="#tranh-phat-hien-quet-su-dung-nhieu-đia-chi-ip-gia" aria-label="Permalink to &quot;Tránh Phát hiện Quét sử dụng Nhiều Địa chỉ IP Giả&quot;">​</a></h1><p>Lệnh Nmap <code>nmap -D RND:10</code> là tùy chọn giả (decoy), cho phép bạn quét sử dụng nhiều địa chỉ IP giả.</p><p>Tường lửa và IDS phát hiện các nỗ lực quét bình thường trên mạng mục tiêu. Tuy nhiên, bạn có thể sử dụng kỹ thuật địa chỉ IP giả để tránh bị phát hiện.</p><p><strong>Trước khi bắt đầu bài lab này, hãy đảm bảo rằng bạn đã bật tường lửa Windows trên máy mục tiêu.</strong></p><h2 id="phan-manh-ip" tabindex="-1">Phân mảnh IP <a class="header-anchor" href="#phan-manh-ip" aria-label="Permalink to &quot;Phân mảnh IP&quot;">​</a></h2><p>Mở một cửa sổ Terminal mới trên Kali và nhập địa chỉ IP mục tiêu (Windows).</p><p><code>nmap -f &lt;địa chỉ IP mục tiêu&gt;</code></p><p><code>-f</code>: Được sử dụng để quét các gói tin phân mảnh nhỏ.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nmap scan report for 10.0.2.23</span></span>
<span class="line"><span>Host is up (0.00074s latency).</span></span>
<span class="line"><span>Not shown: 979 filtered ports</span></span>
<span class="line"><span>PORT      STATE SERVICE</span></span>
<span class="line"><span>53/tcp    open  domain</span></span>
<span class="line"><span>80/tcp    open  http</span></span>
<span class="line"><span>88/tcp    open  kerberos-sec</span></span>
<span class="line"><span>135/tcp   open  msrpc</span></span>
<span class="line"><span>139/tcp   open  netbios-ssn</span></span>
<span class="line"><span>389/tcp   open  ldap</span></span>
<span class="line"><span>443/tcp   open  https</span></span>
<span class="line"><span>445/tcp   open  microsoft-ds</span></span>
<span class="line"><span>464/tcp   open  kpasswd5</span></span>
<span class="line"><span>593/tcp   open  http-rpc-epmap</span></span>
<span class="line"><span>636/tcp   open  ldapssl</span></span>
<span class="line"><span>3268/tcp  open  globalcatLDAP</span></span>
<span class="line"><span>3269/tcp  open  globalcatLDAPssl</span></span>
<span class="line"><span>3389/tcp  open  ms-wbt-server</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Nmap done: 1 IP address (1 host up) scanned in 13.72 seconds</span></span></code></pre></div><p>Khi dịch vụ Windows Firewall được bật, bạn chỉ có thể thấy các cổng mở như hiển thị trong đầu ra ở trên.</p><h2 id="thuc-hien-maximum-transmission-unit" tabindex="-1">Thực hiện Maximum Transmission Unit <a class="header-anchor" href="#thuc-hien-maximum-transmission-unit" aria-label="Permalink to &quot;Thực hiện Maximum Transmission Unit&quot;">​</a></h2><p>Lệnh này được sử dụng để truyền các gói tin nhỏ hơn thay vì gửi một gói tin hoàn chỉnh mỗi lần.</p><p>Quét này rất giống với quét trước nhưng với <strong>Maximum Transmission Unit</strong> (<code>-mtu</code>) và <code>8</code> byte gói tin.</p><p><code>nmap -mtu 8 &lt;địa chỉ IP mục tiêu&gt;</code></p><p>Nếu mọi thứ hoạt động, kết quả sẽ giống hệt với quét trước.</p><h2 id="gia-mao-đia-chi-ip" tabindex="-1">Giả mạo địa chỉ IP <a class="header-anchor" href="#gia-mao-đia-chi-ip" aria-label="Permalink to &quot;Giả mạo địa chỉ IP&quot;">​</a></h2><p>Lệnh này được sử dụng để quét nhiều địa chỉ IP giả. Nmap sẽ gửi nhiều gói tin với các địa chỉ IP khác nhau, cùng với địa chỉ IP kẻ tấn công thực của bạn.</p><p><code>nmap -D RND:10 &lt;địa chỉ IP mục tiêu&gt;</code></p><p>Một lần nữa, đầu ra giống với các đầu ra trước đó nhưng trên góc nhìn của mục tiêu thì rất khác.</p><p>Kiểm tra Nhật ký trên tường lửa Windows Server và phân tích lần quét cuối cùng được thực hiện. Bạn cũng có thể phân tích thông tin này với Wireshark đang bật.</p><p>Cả hai đều hiển thị nhiều địa chỉ IP cùng với địa chỉ IP kẻ tấn công thực của bạn.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6c4f716f549aedea473d2701b1f40bb592413e47/firewallLog-RND.png" alt="firewall"><em>Nhật ký Windows Firewall: Địa chỉ IP Giả</em></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6c4f716f549aedea473d2701b1f40bb592413e47/wireshark-RND.png" alt="wireshark"><em>Wireshark: Địa chỉ IP Giả</em></p>`,23)]))}const d=a(p,[["render",c]]);export{g as __pageData,d as default};
